var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SHOWHOST_NPC_NULL_NULL","text":{"KOREA":"지금 보고 계신 것은 그로니아의 수도, 타나베린의 전경입니다.","JPN":"ただいまご覧になっているのはグロニアの首都、タナベリンの全景です。","ENG":"What you’re looking at is a panoramic view of Tanaberin, the capital of Gronia.","TWN":"現在各位觀眾所看到的，就是格羅尼亞的首都 達那貝林的全景。"},"stage":{"bg":"HARMONY_01_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SHOWHOST_NPC_NULL_NULL","text":{"KOREA":"20년만의 건국절 기념식을 앞두고 건국기념전당 앞은 교통 통제 상태라는데요.","JPN":"20年ぶりの建国記念式を控えて、建国記念館前は交通規制されている状態です。","ENG":"Ahead of the 20th year anniversary celebration of National Foundation Day, traffic control has been deployed in front of the National Foundation Hall.","TWN":"在這裡，即將舉行睽違20年的國慶典禮，因此建國紀念堂前面目前是有交通管制的。"},"stage":{"bg":"HARMONY_01_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PANEL_NPC_NULL_A","text":{"KOREA":"아, 저 건물. 유명했죠. 당시엔 재정 파탄의 원흉이란 비난을 받았습니다만.","JPN":"あ、あの建物。有名でしたね。当時には財政破綻の元凶と責められましたが。","ENG":"Ah, that’s a pretty famous building, right? It was related to a massive economic collapse.","TWN":"喔～那個建築物很有名呢！雖然當時被大家指責是財政破口的原因。"},"stage":{"bg":"HARMONY_01_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PANEL_NPC_NULL_B","text":{"KOREA":"반정부주의 단체들이 내세웠던 가장 큰 명분이기도 하고요.","JPN":"反政府主義団体が掲げた最大の名分でもありますしね。","ENG":"That was one of the biggest arguments put forth by the anti-government troops.","TWN":"這也是最為反政府勢力所詬病的。"},"stage":{"bg":"HARMONY_01_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SHOWHOST_NPC_NULL_NULL","text":{"KOREA":"그런데 내전은 아직 현재진행형 아닙니까? 왜 그로니아는 기념식을 강행하려는 걸까요?","JPN":"ところで内戦はまだ終結してないですよね？　なぜグロニアは記念式を強行するのでしょうか？","ENG":"But isn’t the civil war still ongoing? Why would Gronia want to continue with the ceremony?","TWN":"不過內戰不是現在進行式嗎？為什麼格羅尼亞非要在這個時候舉行典禮呢？"},"stage":{"bg":"HARMONY_01_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PANEL_NPC_NULL_A","text":{"KOREA":"순혈지식 연대의 거점이 공격 받은 뒤로는 반군들이 예전 같지 않죠. 가장 강성했던 세력이었으니까요.","JPN":"純血知識連帯の拠点が攻撃された後から、反乱軍も本調子ではありません。あそこがもっとも強い勢力でしたからね。","ENG":"The rebel forces haven’t been the same ever since the Pureblood Knowledge Regiment’s main base was attacked. It was the hardliner rebels’ largest force.","TWN":"純血知識年代的據點受到攻擊後，叛軍的氣勢就大不如前，畢竟他們是最強盛的勢力。"},"stage":{"bg":"HARMONY_01_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PANEL_NPC_NULL_B","text":{"KOREA":"거점 위치가 유출된 데 대한 책임 소재로 강경파와 온건파의 대립이 심화되었고…….","JPN":"拠点の位置が流出したことに対する責任の所在で、強硬派と穏健派の対立が深まり……","ENG":"Determining who was at fault for leaking the secret location of the base has intensified the conflict between the hardliners and the moderates.","TWN":"據點位置曝光的責任歸屬問題，也加深強硬派和溫和派的對立……"},"stage":{"bg":"HARMONY_01_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PANEL_NPC_NULL_B","text":{"KOREA":"강경파가 기상 조절기를 밀매했다는 사실이 드러나 외부 지원도 끊긴 모양입니다.","JPN":"強硬派が気象調節器を密売したという事実が明らかになって外部からの支援も途絶えたようです。","ENG":"External support has begun to wane after the hardliners were found to have illegally trafficked the weather controller.","TWN":"強硬派走私氣象調節器的事情曝光後，外界的支援似乎也已經中斷。"},"stage":{"bg":"HARMONY_01_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SHOWHOST_NPC_NULL_NULL","text":{"KOREA":"악용하기에 따라서는 침식 현상만큼 무서운 재난을 불러올 수 있을 테니까요.","JPN":"悪用されたら侵食現象ぐらいの恐ろしい厄災を招くでしょうからね。","ENG":"With potential misuse, it could lead to a massive environmental disaster as dangerous as the Counterside Effect.","TWN":"畢竟萬一遭到有心人士的濫用，很可能會造成像是侵蝕現象那樣可怕的災難。"},"stage":{"bg":"HARMONY_01_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SHOWHOST_NPC_NULL_NULL","text":{"KOREA":"본론으로 돌아가서, 그로니아의 건국절 하면 역시 건국기념전당에서 열리는 음악회죠?","JPN":"本題に戻りまして、グロニアの建国記念日といえばやはり建国記念館で開かれる音楽会が欠かせないですよね？","ENG":"Returning to the topic at hand, the highlight of Gronia’s National Foundation Day is a concert held at the National Foundation Hall, correct?","TWN":"回到今天的主題，提到格羅尼亞的國慶典禮，就不能不提到在建國紀念堂的音樂會吧？"},"stage":{"bg":"HARMONY_01_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PANEL_NPC_NULL_A","text":{"KOREA":"그럼요. 내전이 있기 전에는 음악가라면 누구나 평생에 한 번쯤 서고 싶은 자리였죠.","JPN":"ええ。内戦が起こる前は、音楽家であれば一生に一度は立ってみたいという場でした。","ENG":"That’s right. Before the civil war, it was every musician’s dream to one day be able to perform there.","TWN":"那是當然的！在內戰爆發之前，那可是每一個音樂家一生中所追求的最高殿堂呢！"},"stage":{"bg":"HARMONY_01_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PANEL_NPC_NULL_A","text":{"KOREA":"대표적으로 과거 망명했던 클림트 씨가…….","JPN":"代表としては過去、亡命したクリムト氏が……","ENG":"Representative musician is Mr. Klimt who had fled the country in the past...","TWN":"最具代表性的就是先前流亡海外的克里姆……"},"stage":{"bg":"HARMONY_01_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"참 한가한 소리죠? 누군 전쟁터에서 구르다 병원 신세를 지는데 축제를 연다네요.","JPN":"のんきだよね？　こっちは戦場で怪我して病院送りになってるのに、お祭りだなんて。","ENG":"Ahhh. Isn’t this wonderful? Someone’s here rolling an ankle one day on the battlefield, and there’s a festival going on.","TWN":"真是吃飽沒事幹，有人在戰場上拼命結果被送進醫院，有人卻要舉辦國慶典禮？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"물론 전 평범한 꾀병이었지만요.","JPN":"もちろん私はただの仮病だけど。","ENG":"Of course, I completely faked my injury, you know.","TWN":"雖然我是裝病的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"뭐가 아쉽다고 죽을 둥 살 둥 싸워요? 등신도 아니고.","JPN":"何のために死ぬ気で戦うの？　バカじゃあるまいし。","ENG":"What’s wrong with that? You expect me to fight tooth and nail to the end? I’m not an idiot.","TWN":"我還有那麼美好的人生，才不想浪費生命在戰爭上呢！我才沒那麼傻咧！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"효율적으로. 적당적당히. 이 나라에서 생존하려면 모난 구석 없게 살아야 돼요.","JPN":"効率的に。適当に。この国で生きていくには丸く生きないとダメなんだよ。","ENG":"The way to survive in this country is to be efficient and practical.","TWN":"要想安穩地在這個國家生存，還是必須狡猾一點。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이야. 카운터란 걸 숨겨서 참 다행이죠. 어디 덧나도 금방 낫는다니까요.","JPN":"いやあ、カウンターだってこと隠しといてよかった。傷が悪化してもすぐ治るんだからね。","ENG":"It's a good thing that I could hide the fact that I'm a Counter. Even if I get hurt, I just quickly recover.","TWN":"哇～幸好我有隱瞞制裁者的身分，而且我就算受傷也好得很快。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"뒷일 걱정 없이 일부러 다쳐서 군 병원에 입원할 수도 있고. 상이 군인 대접도 받고.","JPN":"後の心配もなくわざと怪我して軍病院に入院もできるし。傷痍軍人扱いされるし。","ENG":"I can get a little injured intentionally, be hospitalized at a military hospital, and still get treated like an honorable combat veteran.","TWN":"這樣我就可以故意受傷被送進軍醫院，大家也都把我當傷兵看待。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"징집될 때 카운터라고 했어 봐. 혼자서 반군 간부들 모가지 따 오라고 보냈을걸.","JPN":"徴集される時カウンターって言ってたら、反乱軍の幹部の首をもって来いって一人で行かされたね。","ENG":"But if I said that I was a Counter when I was drafted, they’ll send me alone on a dangerous mission to take out some rebels.","TWN":"要是我在徵招時承認我是制裁者，肯定立刻被派去取叛軍幹部的首級！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"응? 아까부터 왜 혼자 떠드냐고요?","JPN":"うん？　さっきから一人で何つぶやいてるのかって？","ENG":"What? You’re asking why I’m talking to myself?","TWN":"嗯？我幹嘛一直自言自語喔？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"왜 그러겠어요, 상상 친구 씨. 드디어 이 지긋지긋한 나라를 떠날 수 있어서죠.","JPN":"わからないの？　エア友さん。やっとこのうんざりした国から出られるからだよ。","ENG":"Great question, Mr. Imaginary Friend! Well, because I can finally leave this country.","TWN":"你怎麼這麼說呢？我想像中的朋友，因為我終於可以離開這個討厭的國家啦！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"침대보로 로프를 만들어서 조용히 빠져나간 다음에, 밀입국 브로커랑 접선하면 작전 성공.","JPN":"シーツでロープを作ってこっそり抜け出した後に、密入国のブローカーと接触すれば作戦成功。","ENG":"I’ve made a rope with a bedsheet. Now just gotta slip out quietly. My contact will then smuggle me out of the country. Operation success!","TWN":"我只要用床單做成繩子逃出這裡，再找人蛇仲介偷渡出去，就大功告成啦！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"어차피 사는 게 지옥이라지만 어디든 이 나라보다는 낫겠지.","JPN":"生き地獄って言うけど、どこでもこの国よりはマシだよ。","ENG":"Well, they say the grass is always greener on the other side, but anywhere would be better than this country.","TWN":"雖然生活跟地獄一樣，但不管去哪裡，肯定都比這裡好！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"후후. 그럼 잘 있어라, 내 정든 병실아.","JPN":"ふふ。それじゃあさよなら、私の病室。","ENG":"Ha. Now then, goodbye and be well, my sweet, dear hospital room.","TWN":"嘿嘿，親愛的病房，我們後會無期啦！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"누가 군 병원 아니랄까 봐 환자식은 끔찍하더라.","JPN":"軍病院なだけあって病院食の味はひどかったよ。","ENG":"Oh, and by the way, military hospital food sucks!","TWN":"是怕人家不知道這裡是軍醫院嗎？東西有夠難吃的！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_A","text":{"KOREA":"여기가 크리스티나 브레히트 중사님이 계신 병실 맞습니까?","JPN":"ここがクリスティーナ・ブレヒト軍曹の病室ですか？","ENG":"Is this Christina Brecht’s room?","TWN":"這裡就是克莉絲蒂娜·布萊希特中士的病房嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_GRONIA_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_B","text":{"KOREA":"보안국에서 왔습니다. 실례지만 지금 바로 저희와 함께……","JPN":"保安局から来ました。失礼ですが、今すぐ私たちと一緒に……","ENG":"We’re from the Department of National Security. Excuse me, with me here is...","TWN":"我們是安全局派來的，不好意思，請您現在立刻和我們去一趟……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_GRONIA_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_B","text":{"KOREA":" 어디 가셨지?","JPN":" いない？","ENG":" Wait... Where did she go?","TWN":"人呢？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_GRONIA_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_A","text":{"KOREA":"중사님, 왜 침대보에 매달려 계십니까?","JPN":"軍曹、なぜシーツにぶら下がっているのですか？","ENG":"Sergeant, why are you hanging on the bed sheets?","TWN":"中士，請問您為何要垂掛床單？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_GRONIA_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……가만히 누워 있으려니 몸이 녹슬더라고요. 그래서 재활 훈련으로 좀.","JPN":"……じっと横になっていたら体が鈍くなってしまって。だからちょっとしたリハビリを。","ENG":"...I was feeling super stiff from lying down for so long I decided to do a little physical therapy.","TWN":"……因為一直躺著，躺到我渾身僵硬，想說來復健一下。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_GRONIA_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"보안국? 보안국이 뭐하러 여길 와? 그것도 하필 탈출하려던 지금?","JPN":"保安局？　保安局が何の用？　しかも脱出しようとした矢先に？","ENG":"National Security? Why are they here? Right when I’m making my escape?","TWN":"安全局？安全局的人來幹嘛？而且還偏偏挑我要逃跑的時候？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"꾀병 부리던 게 들켰나? 설마 브로커가 밀고한 거야? 아니면……?","JPN":"仮病がバレた？　まさかブローカーの密告？　それとも……？","ENG":"Did they find out I was faking being sick? Did the smuggler rat me out? Or was it...?","TWN":"難道被發現我是裝病的？是人蛇仲介告密的嗎？還是怎樣……？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"어쩔 수 없지. 일단 침착하자, 크리스. 다들 개죽음당할 때 너만은 살아남았잖아.","JPN":"仕方ない。一旦落ち着け、クリス。みんな無駄死にしてもお前だけは生き延びたんだ。","ENG":"Oh well, it can’t be helped. Wait, calm down, Chris. You were the only survivor while everyone else was killed.","TWN":"先冷靜下來再說，克莉絲你可以的！大家都死光光的時候，就只有你活下來不是嗎！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"제가 크리스티나 브레히트 중사입니다만……. 저 같은 일개 군인에게 보안국이 무슨 일로?","JPN":"私がクリスティーナ・ブレヒト軍曹ですが……私のような一介の軍人に保安局が何のご用ですか？","ENG":"I’m Sergeant Christina Brecht. I’m just a soldier and what’s the National Security coming to see me for?","TWN":"我就是克莉絲蒂娜·布萊希特中士……我不過就是個平凡的軍人，安全局找我有什麼事嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_B","text":{"KOREA":"일개 군인이라니 겸손이 과하십니다.","JPN":"一介の軍人とはご謙遜を。","ENG":"Isn’t it a bit much to call yourself “just a soldier”?","TWN":"什麼平凡的軍人，中士真是太謙卑了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_A","text":{"KOREA":"맞습니다. 반군과의 수많은 격전에서 생환하신 베테랑 아니십니까.","JPN":"そのとおりです。反乱軍との数多くの激戦から生還されたベテランではありませんか。","ENG":"Right. Aren’t you a combat veteran that’s survived countless battles with the rebels?","TWN":"沒錯，您可是在無數次和叛軍的激戰中存活下來的勇士呢！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……아.","JPN":"……あ。","ENG":"...Ah.","TWN":"喔……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_B","text":{"KOREA":"파레마 탈환전의 유일한 생환자셨다죠? 정말 치열한 전투라고 들었습니다.","JPN":"パレマ奪還戦の唯一の生還者でしょう？　とても激しい戦闘だったと聞きました。","ENG":"You were the only survivor of the recapturing of Parema, weren’t you? It was said to be a fierce battle.","TWN":"您是奪回波雷馬之戰中唯一的倖存者吧？我聽說那場戰役非常激烈呢！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아니, 저는 그냥 운 좋게…….","JPN":"いや、私はただ運がよかっただけで……","ENG":"Oh no, I was just lucky...","TWN":"沒有啦，我只是運氣好……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_A","text":{"KOREA":"부상이 회복되자마자 다시 전쟁터로 돌아가셨고 말입니다.","JPN":"怪我が回復するなり再び戦場にお戻りになって。","ENG":"It’s said as soon as you recovered from your injuries, you returned to the battlefield.","TWN":"而且身體一復原就立刻回到戰場上。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그건 그냥 지휘관 인성이 썩어서…….","JPN":"それはただ指揮官がクソで……","ENG":"Uhh, it’s just that the commander’s personality was so scary, so...","TWN":"那只是因為指揮官太沒人性……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_B","text":{"KOREA":"수도에 중사님 같은 분이 계셔서 다행입니다!","JPN":"首都に軍曹のような方がいらっしゃってよかったです！","ENG":"We’re so fortunate to have someone like you in the capital!","TWN":"幸好首都裡有像中士這樣的人才！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SOLDIER_GRONIA_NULL_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_A","text":{"KOREA":"입원 중일 때도 군복 차림으로 계시다니……. 역시 무공훈장의 주인다우십니다.","JPN":"入院中にまで軍服姿とは……やはり勲章の主としてふさわしいお方です。","ENG":"You’re even remaining in military uniform while in the hospital... No wonder you’re a recipient of the Medal of Honor.","TWN":"住院時也穿著軍裝……真不愧是授勳的軍人！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SOLDIER_GRONIA_NULL_B","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_GRONIA_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이 인간들……. 뭔가 단단히 잘못 알고 있네.","JPN":"この人たち……なんか勘違いしてるね。","ENG":"These guys... They’re getting hold of the wrong end of the stick.","TWN":"這些人……是不是有什麼誤會？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"누가 봐도 도망치는 거잖아? 화약 냄새에 이성이 마비됐나? 그런 거야?","JPN":"これってどう見てもとんずらだよね？　火薬の匂いで頭が麻痺してる？　そうなの？","ENG":"I’m obviously running away. Has the smell of gunpowder messed with their brain? For real?","TWN":"看也知道我是想逃吧？你們是火藥味聞太多，導致喪失判斷能力嗎？是這樣嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……라고 지적해 주고는 싶지만, 그랬다간 내 발로 심문실에서 못 걸어나오겠지.","JPN":"……って突っ込みたいけど、それじゃあ自分の足で尋問室から出られないだろう。","ENG":"...is what I’d like to say, but then I wouldn’t even be able to walk after what they’d do to me in interrogation.","TWN":"……雖然很想這樣罵他們，但這樣我應該會走不出審訊室吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"물론이죠. 조국의 평화를 위해 싸우고 싶어서 지금도 몸이 근질거릴 정도입니다.","JPN":"もちろんです。国の平和のために戦いたくて今も腕が鳴っているところです。","ENG":"Right! I want to fight for peace and glory of my country, my body is itching to get back to it even now.","TWN":"那是當然的！就算我現在在病房裡，心裡想的還是保家衛國呢！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_A","text":{"KOREA":"오오……. 나이와 상관없는 훌륭한 군인 정신…….","JPN":"おお……年齢に見合わない素晴らしい軍人精神……","ENG":"Ooh...! Truly a great hero of the battlefield despite being so young...","TWN":"哇喔……看您年紀輕輕，卻有如此感人的愛國情操……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_B","text":{"KOREA":"저희들도 중사님을 본받기 위해 노력해야겠군요.","JPN":"私たちも軍曹を見習うべく努力しないといけませんね。","ENG":"We should all do our best to emulate Sergeant’s great example.","TWN":"我們也應該要以中士為榜樣，好好努力！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……아, 네. 그거 감사해서 몸둘 바를 모르겠네요.","JPN":"……あ、はい。ありがたくてどうすればいいか。","ENG":"...Ah, right. How nice of you to say that.","TWN":"……別這麼說，我何德何能成為你們的榜樣！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그래서……. 정말 무슨 일로 절 찾아 오신 거죠?","JPN":"それで……本当に私になんの用ですか？","ENG":"So, uh... what brings you here?","TWN":"所以……你們找我到底有什麼事呢？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};